@@ -0,0 +1,68 @@
+import type { EventSubscription } from "expo-modules-core";
+import { Accelerometer } from "expo-sensors";
+import { useEffect, useState } from "react";
+import { Text, TouchableOpacity, View } from "react-native";
+
+export default function App() {
+  const [{ x, y, z }, setData] = useState({
+    x: 0,
+    y: 0,
+    z: 0,
+  });
+
+  const [subscription, setSubscription] =
+    useState<EventSubscription | null>(null);
+
+  const _slow = () => Accelerometer.setUpdateInterval(120);
+  const _fast = () => Accelerometer.setUpdateInterval(50);
+
+  const magnitude = Math.sqrt(x*x + y*y + z*z);
+
+  /* wenn Handy geschüttelt wird, steigt die acceleration
+     minus 1, weil Handy in Ruhezustand 1g misst, den muss man abziehen
+  */
+  const acceleration = Math.abs(magnitude - 1);
+
+  const _subscribe = () => {
+    setSubscription(
+      Accelerometer.addListener((data) => {
+        setData(data);
+      })
+    );
+  };
+
+  const _unsubscribe = () => {
+    subscription?.remove();
+    setSubscription(null);
+  };
+
+  useEffect(() => {
+    _subscribe();
+
+    return () => {
+      subscription?.remove();
+    };
+  }, []);
+
+  return (
+    <View>
+      <Text>Accelerometer:</Text>
+      <Text>x: {x}</Text>
+      <Text>y: {y}</Text>
+      <Text>z: {z}</Text>
+      <Text>Acceleration: {acceleration}</Text>
+
+      <TouchableOpacity onPress={subscription ? _unsubscribe : _subscribe}>
+        <Text>{subscription ? "On" : "Off"}</Text>
+      </TouchableOpacity>
+
+      <TouchableOpacity onPress={_slow}>
+        <Text>Slow</Text>
+      </TouchableOpacity>
+
+      <TouchableOpacity onPress={_fast}>
+        <Text>Fast</Text>
+      </TouchableOpacity>
+    </View>
+  );
+}
