+import { Accelerometer } from "expo-sensors";
+import { useEffect, useState } from "react";
+import { Dimensions, Text, TouchableOpacity, View } from "react-native";
+import { LineChart } from "react-native-chart-kit";
+
+export default function App() {
+  const [{ x, y, z }, setData] = useState({
+    x: 0,
+    y: 0,
+    z: 0,
+  });
+
+  const [subscription, setSubscription] =
+    useState<EventSubscription | null>(null);
+
+
+
+  /* wenn Handy geschüttelt wird, steigt die acceleration
+  minus 1, weil Handy in Ruhezustand 1g misst, den muss man abziehen
+  */
+  /* Array um die letzte Werte speichern */
+  const [samples, setSamples] = useState<number[]>([]);
+  /* Datenmenge begrenzen */
+
+
+  const _subscribe = () => {
+    setSubscription(
+      Accelerometer.addListener((data) => {
+        setData(data);
+        Accelerometer.setUpdateInterval(50);
+        const magnitude = Math.sqrt(data.x * data.x + data.y * data.y + data.z * data.z);
+        const acceleration = Math.abs(magnitude - 1);
+        setSamples(prev => [...prev, acceleration].slice(-100));
+      })
+    );
+  };
+
+  const _unsubscribe = () => {
+    subscription?.remove();
+    setSubscription(null);
+  };
+
+  useEffect(() => {
+    _subscribe();
+
+    return () => {
+      subscription?.remove();
+    };
+  }, []);
+
+  return (
+    <View>
+      <Text>Accelerometer:</Text>
+      <Text>x: {x}</Text>
+      <Text>y: {y}</Text>
+      <Text>z: {z}</Text>
+
+      <TouchableOpacity onPress={subscription ? _unsubscribe : _subscribe}>
+        <Text>{subscription ? "On" : "Off"}</Text>
+      </TouchableOpacity>
+
+      <LineChart
+        data={{
+          labels: [],
+          datasets: [{ data: samples.length ? samples : [0] }],
+        }}
+        width={Dimensions.get("window").width - 20}
+        height={220}
+        withDots={false}
+        withShadow={false}
+        withInnerLines={false}
+        withOuterLines={true}
+        fromZero={false}
+        segments={6}
+        yAxisInterval={1}
+        chartConfig={{
+          backgroundGradientFrom: "#fff",
+          backgroundGradientTo: "#fff",
+          decimalPlaces: 2,
+          color: () => "blue",
+          labelColor: () => "black",
+          propsForBackgroundLines: {
+            stroke: "transparent",
+          },
+          propsForLabels: {
+            fontSize: 10,
+          },
+          propsForDots: {
+            r: "0",
+          },
+        }}
+        bezier={false}
+        style={{
+          borderWidth: 1,
+          borderColor: "black",
+          paddingRight: 0,
+        }}
+      />
+    </View>
+  );
+}
